#include <stdio.h>
#include <stdlib.h>

int main() {
    int N;
    scanf("%d", &N);
    int* arr = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    int count = 0;
    for (int i = 0; i < N; i++) {
        int found = 0;
        for (int j = 0; j < N; j++) {
            for (int k = 0; k < N; k++) {
                if (j != k && j != i && k != i) {
                    if ((arr[j] + arr[k]) / 2.0 == arr[i]) {
                        found = 1;
                        break;
                    }
                }
            }
            if (found) break;
        }
        if (found) count++;
    }
    printf("%d\n", count);
    free(arr);
    return 0;
}

